using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers see all, customers see their own)
        group.MapGet("/", async (ApplicationDbContext db, HttpContext ctx) =>
        {
            var userId = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
            var user = await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);

            IQueryable<Shipment> query = db.Shipments.OrderByDescending(s => s.ShippedDate);

            if (user is not { IsDispatcher: true })
            {
                var email = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value ?? "";
                query = query.Where(s => s.RecipientEmail == email);
            }

            return Results.Ok(await query.Select(s => MapToDto(s)).ToListAsync());
        });

        // Get single shipment by tracking number (public lookup)
        group.MapGet("/track/{trackingNumber}", [AllowAnonymous] async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(MapToDto(shipment));
        });

        // Get single shipment by id
        group.MapGet("/{id:int}", async (int id, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(MapToDto(shipment));
        });

        // Create shipment (dispatchers only)
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db, HttpContext ctx) =>
        {
            var userId = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
            var user = await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);
            if (user is not { IsDispatcher: true })
                return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = (ShipmentStatus)(int)dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                RecipientEmail = dto.RecipientEmail,
                DispatcherNotes = dto.DispatcherNotes,
                AssignedDispatcherId = userId
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", MapToDto(shipment));
        });

        // Update shipment (dispatchers only)
        group.MapPut("/{id:int}", async (int id, ShipmentDto dto, ApplicationDbContext db, HttpContext ctx) =>
        {
            var userId = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
            var user = await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);
            if (user is not { IsDispatcher: true })
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Origin = dto.Origin;
            shipment.Destination = dto.Destination;
            shipment.Status = (ShipmentStatus)(int)dto.Status;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            shipment.RecipientName = dto.RecipientName;
            shipment.RecipientEmail = dto.RecipientEmail;
            shipment.DispatcherNotes = dto.DispatcherNotes;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        });

        // Delete shipment (dispatchers only)
        group.MapDelete("/{id:int}", async (int id, ApplicationDbContext db, HttpContext ctx) =>
        {
            var userId = ctx.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
            var user = await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);
            if (user is not { IsDispatcher: true })
                return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (Client.Models.ShipmentStatus)(int)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail,
        DispatcherNotes = s.DispatcherNotes
    };
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync();
    Task<ShipmentDto?> GetShipmentAsync(int id);
    Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber);
    Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment);
    Task<ShipmentDto?> UpdateShipmentAsync(ShipmentDto shipment);
    Task<bool> DeleteShipmentAsync(int id);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var response = await http.GetAsync($"/api/shipments/{id}");
        return response.IsSuccessStatusCode
            ? await response.Content.ReadFromJsonAsync<ShipmentDto>()
            : null;
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        return response.IsSuccessStatusCode
            ? await response.Content.ReadFromJsonAsync<ShipmentDto>()
            : null;
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", shipment);
        return response.IsSuccessStatusCode
            ? await response.Content.ReadFromJsonAsync<ShipmentDto>()
            : null;
    }

    public async Task<ShipmentDto?> UpdateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{shipment.Id}", shipment);
        return response.IsSuccessStatusCode
            ? await response.Content.ReadFromJsonAsync<ShipmentDto>()
            : null;
    }

    public async Task<bool> DeleteShipmentAsync(int id)
    {
        var response = await http.DeleteAsync($"/api/shipments/{id}");
        return response.IsSuccessStatusCode;
    }
}

