@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="mb-3 d-flex gap-2">
    <input class="form-control" style="max-width:300px" placeholder="Filter by destination..."
           @bind="filterText" @bind:event="oninput" />
    <select class="form-select" style="max-width:200px" @bind="filterStatus">
        <option value="">All Statuses</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (isLoading)
{
    <p><em>Loading shipments...</em></p>
}
else if (filteredShipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Recipient</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in filteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                        <td>@s.RecipientName</td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => EditShipment(s)">Edit</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteShipment(s.Id)">Delete</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (showForm)
{
    <div class="card mt-3 p-3">
        <h4>@(isEditing ? "Edit Shipment" : "New Shipment")</h4>
        <EditForm Model="currentShipment" OnValidSubmit="SaveShipment" FormName="shipmentForm">
            <DataAnnotationsValidator />
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Tracking Number</label>
                    <InputText class="form-control" @bind-Value="currentShipment.TrackingNumber" disabled="@isEditing" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <InputText class="form-control" @bind-Value="currentShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <InputText class="form-control" @bind-Value="currentShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Status</label>
                    <InputSelect class="form-select" @bind-Value="currentShipment.Status">
                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                        {
                            <option value="@status">@status</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Shipped Date</label>
                    <InputDate class="form-control" @bind-Value="currentShipment.ShippedDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <InputDate class="form-control" @bind-Value="currentShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <InputText class="form-control" @bind-Value="currentShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Email</label>
                    <InputText class="form-control" @bind-Value="currentShipment.RecipientEmail" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Notes</label>
                    <InputText class="form-control" @bind-Value="currentShipment.DispatcherNotes" />
                </div>
            </div>
            <div class="mt-3">
                <button type="submit" class="btn btn-success">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
            </div>
        </EditForm>
    </div>
}

@code {
    private List<ShipmentDto> shipments = [];
    private string filterText = "";
    private string filterStatus = "";
    private bool isLoading = true;
    private bool showForm;
    private bool isEditing;
    private ShipmentDto currentShipment = new();

    private List<ShipmentDto> filteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus)
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
        isLoading = false;
    }

    private void ShowCreateForm()
    {
        currentShipment = new ShipmentDto
        {
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(5)
        };
        isEditing = false;
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        currentShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            RecipientName = shipment.RecipientName,
            RecipientEmail = shipment.RecipientEmail,
            DispatcherNotes = shipment.DispatcherNotes
        };
        isEditing = true;
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (isEditing)
        {
            var updated = await ShipmentService.UpdateShipmentAsync(currentShipment);
            if (updated is not null)
            {
                var idx = shipments.FindIndex(s => s.Id == updated.Id);
                if (idx >= 0) shipments[idx] = updated;
            }
        }
        else
        {
            var created = await ShipmentService.CreateShipmentAsync(currentShipment);
            if (created is not null) shipments.Insert(0, created);
        }
        showForm = false;
    }

    private async Task DeleteShipment(int id)
    {
        if (await ShipmentService.DeleteShipmentAsync(id))
            shipments.RemoveAll(s => s.Id == id);
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>

<div class="mb-3">
    <input class="form-control" style="max-width:300px" placeholder="Search shipments..."
           @bind="searchText" @bind:event="oninput" />
</div>

@if (isLoading)
{
    <p><em>Loading your shipments...</em></p>
}
else if (filteredShipments.Count == 0)
{
    <div class="alert alert-info">No shipments found for your account.</div>
}
else
{
    <div class="row">
        @foreach (var s in filteredShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between">
                        <code>@s.TrackingNumber</code>
                        <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>From:</strong> @s.Origin</p>
                        <p class="mb-1"><strong>To:</strong> @s.Destination</p>
                        <p class="mb-1"><strong>Shipped:</strong> @s.ShippedDate.ToString("MMM dd, yyyy")</p>
                        <p class="mb-0"><strong>Estimated Delivery:</strong></p>
                        <p class="fs-5 text-primary mb-0">@s.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    </div>
                    <div class="card-footer">
                        <small class="text-muted">
                            @GetDeliveryMessage(s)
                        </small>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto> shipments = [];
    private string searchText = "";
    private bool isLoading = true;

    private List<ShipmentDto> filteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(searchText)
            || s.TrackingNumber.Contains(searchText, StringComparison.OrdinalIgnoreCase)
            || s.Destination.Contains(searchText, StringComparison.OrdinalIgnoreCase))
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
        isLoading = false;
    }

    private static string GetDeliveryMessage(ShipmentDto s) => s.Status switch
    {
        ShipmentStatus.Delivered => "Your package has been delivered!",
        ShipmentStatus.OutForDelivery => "Out for delivery today!",
        ShipmentStatus.Delayed => "Delivery delayed. New estimate shown above.",
        _ => $"{(s.EstimatedDelivery - DateTime.UtcNow).Days} days until estimated delivery"
    };

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track a Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p>Enter your tracking number below to see current status and estimated delivery.</p>

<div class="d-flex gap-2 mb-4" style="max-width:500px">
    <input class="form-control" placeholder="e.g. TRK-123456"
           @bind="trackingNumber" @onkeydown="HandleKeyDown" />
    <button class="btn btn-primary" @onclick="DoTrack" disabled="@isSearching">
        @(isSearching ? "Searching..." : "Track")
    </button>
</div>

@if (notFound)
{
    <div class="alert alert-warning">No shipment found with tracking number <strong>@searchedNumber</strong>.</div>
}

@if (result is not null)
{
    <div class="card" style="max-width:600px">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking:</strong> <code>@result.TrackingNumber</code></span>
            <span class="badge @GetStatusBadge(result.Status) fs-6">@result.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-6">
                    <p><strong>Origin:</strong><br/>@result.Origin</p>
                </div>
                <div class="col-6">
                    <p><strong>Destination:</strong><br/>@result.Destination</p>
                </div>
                <div class="col-6">
                    <p><strong>Shipped:</strong><br/>@result.ShippedDate.ToString("MMM dd, yyyy")</p>
                </div>
                <div class="col-6">
                    <p><strong>Estimated Delivery:</strong><br/>
                    <span class="fs-5 text-primary">@result.EstimatedDelivery.ToString("MMM dd, yyyy")</span></p>
                </div>
                <div class="col-12">
                    <p><strong>Recipient:</strong> @result.RecipientName</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isSearching;
    private bool notFound;
    private ShipmentDto? result;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await DoTrack();
    }

    private async Task DoTrack()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        notFound = false;
        result = null;
        searchedNumber = trackingNumber.Trim();

        result = await ShipmentService.TrackShipmentAsync(searchedNumber);
        notFound = result is null;
        isSearching = false;
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

