                    <label class="form-label">Shipped Date</label>
                    <InputDate class="form-control" @bind-Value="currentShipment.ShippedDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <InputDate class="form-control" @bind-Value="currentShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <InputText class="form-control" @bind-Value="currentShipment.RecipientName" />
                </div>
