@code {
    private List<ShipmentDto> shipments = [];
    private string filterText = "";
    private string filterStatus = "";
    private bool isLoading = true;
    private bool showForm;
    private bool isEditing;
    private ShipmentDto currentShipment = new();

    private List<ShipmentDto> filteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(filterStatus) || s.Status.ToString() == filterStatus)
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync();
        isLoading = false;
    }

    private void ShowCreateForm()
    {
        currentShipment = new ShipmentDto
        {
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = DateTime.UtcNow.AddDays(5)
        };
        isEditing = false;
        showForm = true;
    }

    private void EditShipment(ShipmentDto shipment)
    {
        currentShipment = new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            RecipientName = shipment.RecipientName,
            RecipientEmail = shipment.RecipientEmail,
            DispatcherNotes = shipment.DispatcherNotes
        };
        isEditing = true;
        showForm = true;
    }

    private async Task SaveShipment()
    {
        if (isEditing)
        {
            var updated = await ShipmentService.UpdateShipmentAsync(currentShipment);
            if (updated is not null)
            {
                var idx = shipments.FindIndex(s => s.Id == updated.Id);
                if (idx >= 0) shipments[idx] = updated;
            }
        }
        else
        {
            var created = await ShipmentService.CreateShipmentAsync(currentShipment);
            if (created is not null) shipments.Insert(0, created);
        }
        showForm = false;
    }

    private async Task DeleteShipment(int id)
    {
        if (await ShipmentService.DeleteShipmentAsync(id))
            shipments.RemoveAll(s => s.Id == id);
    }

    private void CancelForm() => showForm = false;

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

