@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track a Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p>Enter your tracking number below to see current status and estimated delivery.</p>

<div class="d-flex gap-2 mb-4" style="max-width:500px">
    <input class="form-control" placeholder="e.g. TRK-123456"
           @bind="trackingNumber" @onkeydown="HandleKeyDown" />
    <button class="btn btn-primary" @onclick="DoTrack" disabled="@isSearching">
        @(isSearching ? "Searching..." : "Track")
    </button>
</div>

@if (notFound)
{
    <div class="alert alert-warning">No shipment found with tracking number <strong>@searchedNumber</strong>.</div>
}

@if (result is not null)
{
    <div class="card" style="max-width:600px">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span><strong>Tracking:</strong> <code>@result.TrackingNumber</code></span>
            <span class="badge @GetStatusBadge(result.Status) fs-6">@result.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-6">
                    <p><strong>Origin:</strong><br/>@result.Origin</p>
                </div>
                <div class="col-6">
                    <p><strong>Destination:</strong><br/>@result.Destination</p>
                </div>
                <div class="col-6">
                    <p><strong>Shipped:</strong><br/>@result.ShippedDate.ToString("MMM dd, yyyy")</p>
                </div>
                <div class="col-6">
                    <p><strong>Estimated Delivery:</strong><br/>
                    <span class="fs-5 text-primary">@result.EstimatedDelivery.ToString("MMM dd, yyyy")</span></p>
                </div>
                <div class="col-12">
                    <p><strong>Recipient:</strong> @result.RecipientName</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private bool isSearching;
    private bool notFound;
    private ShipmentDto? result;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await DoTrack();
    }

    private async Task DoTrack()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        notFound = false;
        result = null;
        searchedNumber = trackingNumber.Trim();

        result = await ShipmentService.TrackShipmentAsync(searchedNumber);
        notFound = result is null;
        isSearching = false;
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

