using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation that queries the database directly (used during SSR prerendering).
/// </summary>
public class ServerShipmentService(ApplicationDbContext db, IHttpContextAccessor httpContextAccessor) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        var ctx = httpContextAccessor.HttpContext;
        var userId = ctx?.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
        var user = userId is null ? null : await db.Users.OfType<ApplicationUser>().FirstOrDefaultAsync(u => u.Id == userId);

        IQueryable<Shipment> query = db.Shipments.OrderByDescending(s => s.ShippedDate);

        if (user is not { IsDispatcher: true })
        {
            var email = ctx?.User.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value ?? "";
            query = query.Where(s => s.RecipientEmail == email);
        }

        return await query.Select(s => MapToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = dto.TrackingNumber,
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = (ShipmentStatus)(int)dto.Status,
            ShippedDate = dto.ShippedDate,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            RecipientEmail = dto.RecipientEmail,
            DispatcherNotes = dto.DispatcherNotes
        };
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    public async Task<ShipmentDto?> UpdateShipmentAsync(ShipmentDto dto)
    {
        var shipment = await db.Shipments.FindAsync(dto.Id);
        if (shipment is null) return null;

        shipment.Origin = dto.Origin;
        shipment.Destination = dto.Destination;
        shipment.Status = (ShipmentStatus)(int)dto.Status;
        shipment.EstimatedDelivery = dto.EstimatedDelivery;
        shipment.RecipientName = dto.RecipientName;
        shipment.RecipientEmail = dto.RecipientEmail;
        shipment.DispatcherNotes = dto.DispatcherNotes;

        await db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    public async Task<bool> DeleteShipmentAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is null) return false;
        db.Shipments.Remove(shipment);
        await db.SaveChangesAsync();
        return true;
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (Client.Models.ShipmentStatus)(int)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail,
        DispatcherNotes = s.DispatcherNotes
    };
}

