using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        if (await db.Shipments.AnyAsync()) return;

        var shipments = new List<Shipment>
        {
            new()
            {
                TrackingNumber = "TRK-100001",
                Origin = "New York, USA",
                Destination = "London, UK",
                Status = ShipmentStatus.InTransit,
                ShippedDate = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                RecipientName = "Alice Johnson",
                RecipientEmail = "alice@example.com"
            },
            new()
            {
                TrackingNumber = "TRK-100002",
                Origin = "Tokyo, Japan",
                Destination = "Sydney, Australia",
                Status = ShipmentStatus.OutForDelivery,
                ShippedDate = DateTime.UtcNow.AddDays(-5),
                EstimatedDelivery = DateTime.UtcNow,
                RecipientName = "Bob Smith",
                RecipientEmail = "bob@example.com"
            },
            new()
            {
                TrackingNumber = "TRK-100003",
                Origin = "Berlin, Germany",
                Destination = "Paris, France",
                Status = ShipmentStatus.Delivered,
                ShippedDate = DateTime.UtcNow.AddDays(-7),
                EstimatedDelivery = DateTime.UtcNow.AddDays(-2),
                RecipientName = "Claire Dupont",
                RecipientEmail = "claire@example.com"
            },
            new()
            {
                TrackingNumber = "TRK-100004",
                Origin = "Shanghai, China",
                Destination = "Los Angeles, USA",
                Status = ShipmentStatus.Delayed,
                ShippedDate = DateTime.UtcNow.AddDays(-10),
                EstimatedDelivery = DateTime.UtcNow.AddDays(3),
                RecipientName = "David Lee",
                RecipientEmail = "david@example.com",
                DispatcherNotes = "Customs hold - expected clearance tomorrow"
            },
            new()
            {
                TrackingNumber = "TRK-100005",
                Origin = "Mumbai, India",
                Destination = "Dubai, UAE",
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = DateTime.UtcNow.AddDays(6),
                RecipientName = "Fatima Al-Rashid",
                RecipientEmail = "fatima@example.com"
            }
        };

        db.Shipments.AddRange(shipments);
        await db.SaveChangesAsync();
    }
}

